def run(controller):
    controller.reset()
    controller.set_temperature(10.0)
    controller.wait_stable(0.05)
    controller.set_current(0.001)

    settle = 0.2
    max_attempts = 10
    result = None
    for attempt in range(max_attempts):
        sweep_result = controller.sweep_field(-1.0, 1.0, 9, settle)
        if not isinstance(sweep_result, dict):
            result = sweep_result
            break
        settle_ok = sweep_result.get("settle_ok", True)
        if not settle_ok:
            settle *= 2.0
        else:
            result = sweep_result
            break

    controller.disable_current()
    if isinstance(result, dict):
        return result
    return {}

